#include "bme280_sensor.h"
#include <Wire.h>
#include <Adafruit_BME280.h>
#include "config.h"

static Adafruit_BME280 _bme;
static bool _bmeReady = false;
static float _temp = 0, _hum = 0, _press = 0, _alt = 0;
static const float SEA_LEVEL_HPA = 1013.25f;

void bme280_setup() {
    Wire.begin(21, 22);
    Wire.setClock(100000); // 100kHz for reliability

    // Retry initialization up to 5 times
    for (int i = 0; i < 5; i++) {
        if (_bme.begin(0x76, &Wire)) {
            _bmeReady = true;
            break;
        }
        Serial.printf("[bme280] Init attempt %d failed\n", i + 1);
        delay(100);
    }

    if (_bmeReady) {
        // Set oversampling for best accuracy
        _bme.setSampling(
            Adafruit_BME280::MODE_NORMAL,
            Adafruit_BME280::SAMPLING_X16,  // temp
            Adafruit_BME280::SAMPLING_X16,  // pressure
            Adafruit_BME280::SAMPLING_X16,  // humidity
            Adafruit_BME280::FILTER_X16,
            Adafruit_BME280::STANDBY_MS_500
        );
        Serial.println("[bme280] Initialized with x16 oversampling");
    } else {
        Serial.println("[bme280] FAILED - check wiring!");
    }
}

void bme280_loop() {
    if (!_bmeReady) return;
    _temp = _bme.readTemperature();
    _hum = _bme.readHumidity();
    _press = _bme.readPressure() / 100.0f;
    _alt = _bme.readAltitude(SEA_LEVEL_HPA);

    // Sanity check for anomalous readings
    if (_temp < -40.0f || _temp > 85.0f) {
        Serial.println("[bme280] WARNING: Temperature out of range, re-initializing...");
        _bmeReady = false;
        bme280_setup();
    }
}

float bme280_temperature() { return _temp; }
float bme280_humidity() { return _hum; }
float bme280_pressure() { return _press; }
float bme280_altitude() { return _alt; }
bool bme280_ready() { return _bmeReady; }
